# [doc = " The `EXPLAIN` of a built spore: the identity receipt, the surface, the code by hash, the"] # [doc = " dependency edges, and the metadata explicitly marked *not* identity (ADR-003 / C3 / G11)."] # [doc = ""] # [doc = " Returns a human-readable diagnostic string. The same spore always produces the same output"] # [doc = " (total function of the manifest + resolved DAG — no randomness, no IO)."] # [doc = ""] # [doc = " # Guarantee tag: `Exact` (deterministic; a total function of manifest + DAG)"] # [doc = " # Fallibility: total"] # [doc = " # Effects: none"] # [must_use] pub fn explain_spore (spore : & SporeUnit) -> String { let mut out = mycelium_spore :: explain (& spore . raw) ; if let Some (m) = & spore . manifest { out . push_str (& format ! ("  reconstruction manifest: {m}
")) ; out . push_str (& format ! ("  manifest hash: {}
" , m . manifest_hash () . as_str ())) ; out . push_str (& format ! ("  declared strength: {:?}
" , m . declared_strength ())) ; } else { out . push_str ("  reconstruction manifest: none
") ; } out }
